// Automatically handles nested 'body' data from n8n webhooks!
const json = $input.item.json.body || $input.item.json;
const text = json.campaign_report || '';

// Split the markdown by standard H2/H3 headers
const sections = text.split(/\n##?\s+/);

let research = '';
let contentStrategy = '';
let paidAds = '';

for (const section of sections) {
  const lines = section.split('\n');
  const title = lines[0].toLowerCase();

  if (title.includes('research') || title.includes('trend')) {
    research = '## ' + section.trim();
  } else if (title.includes('content') || title.includes('social') || title.includes('write')) {
    contentStrategy = '## ' + section.trim();
  } else if (title.includes('ad') || title.includes('paid') || title.includes('budget')) {
    paidAds = '## ' + section.trim();
  }
}

if (!research) research = text;
if (!contentStrategy) contentStrategy = text;

// Extract LinkedIn & Instagram specific sections
let linkedin = '';
const liMatch = contentStrategy.match(/(?:LinkedIn|Professional Post):?\s*([\s\S]*?)(?=\n(?:Twitter|Instagram|X|Post 2)|$)/i);
linkedin = liMatch ? liMatch[1].trim() : contentStrategy;

let instagram = '';
const igMatch = contentStrategy.match(/(?:Instagram|IG Caption):?\s*([\s\S]*?)(?=\n(?:LinkedIn|Twitter|X|Post)|$)/i);
instagram = igMatch ? igMatch[1].trim() : contentStrategy;

return {
  json: {
    brand_name: json.brand_name || 'N/A',
    product_name: json.product_name || 'N/A',
    target_audience: json.target_audience || 'N/A',
    marketing_goal: json.marketing_goal || 'N/A',
    campaign_budget: json.campaign_budget || 'N/A',
    research_brief: research,
    content_strategy: contentStrategy,
    paid_ads_strategy: paidAds,
    linkedin_post: linkedin,
    instagram_caption: instagram
  }
};

